import{_ as i,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"05. Indicative Position Description For After Hours Coordinator","description":"","frontmatter":{"title":"05. Indicative Position Description For After Hours Coordinator","eba":"Nurses and Midwives 2024-2028","topics":["appendices","classifications"]},"headers":[],"relativePath":"ebas/nurses-midwives/appendices/05-indicative-position-description-for-after-hours-coordinator.md","filePath":"ebas/nurses-midwives/appendices/05-indicative-position-description-for-after-hours-coordinator.md"}'),s={name:"ebas/nurses-midwives/appendices/05-indicative-position-description-for-after-hours-coordinator.md"};function r(a,e,p,d,c,f){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_05-indicative-position-description-for-after-hours-coordinator" tabindex="-1">05. Indicative Position Description For After Hours Coordinator <a class="header-anchor" href="#_05-indicative-position-description-for-after-hours-coordinator" aria-label="Permalink to &quot;05. Indicative Position Description For After Hours Coordinator&quot;">​</a></h1><p>Formatting note</p><p>The appendix body below is rendered in a monospaced block to preserve the column layout of pay tables and classification grids. The block is excluded from the search index so search results stay short; find appendices by their title, number, topic or synonyms.</p><p>```text – INDICATIVE POSITION DESCRIPTION FOR AFTER HOURS COORDINATOR</p><p>POSITION PROFILE • The Supervisor will support and promote activities which are consistent with the objectives and philosophy of the Hospital.</p><p>• Act as a resource for staff (nursing, medical and others) and patients and their families.</p><p>• Being actively involved in the preparation, maintenance and implementation of emergency disaster plans, and together with other emergency control personnel, be responsible for coordination of staff and patient movement in the event of an emergency during their rostered shift(s).</p><p>• Liaise with Admitting Officer, to discuss bed availability and suitable patient placement.</p><p>• Facilitate the resolution of public relations issues as they arise, informing the CEO and/or DON as appropriate.</p><p>• Assist in the delivery of safe patient care by liaising with the Charge Nurse and supporting ward areas with appropriate nursing staff (includes adequate PSA support, orderlies, etc.).</p><p>• Responsible for quality control for nursing services delivered and allocation of staff during their rostered shift(s).</p><p>SPECIFIC RESPONSIBILITIES • Liaise with all staff acting as resource for staff, facilitating and promoting quality patient care.</p><p>• Co-ordinates and maintains appropriate nursing staff levels through consultation with clinical nurses, redeploying staff and engaging nurse bank Employees/agency staff as required.</p><p>• Facilitates the process to ensure the performance and skills of nurse bank Employees are maintained in accordance with hospital policy.</p><p>• Facilitates patient admission by discussing bed availability with the Admitting Officer in accordance with hospital policy.</p><p>• Liaises with emergency department nursing staff, Admitting Officer and operating suite staff to maintain an efficient after-hours emergency surgery service.</p><p>• Ensures the smooth release of bodies from the mortuary after hours when necessary for coronial or religious reasons.</p><p>• To be an active manner on the Emergency Procedures Committee or local equivalent, ensuring nursing input and profile is maintained.</p><p>• Responsible for maintaining own education relating to emergency and disaster procedures.</p><p>• Maintains an awareness of patient/nurse dependency throughout the shift as this will assist the safe co-ordination of staff and patients in such a situation.</p><p>• Assists with the monitoring and analyses of patient incidents and accidents.</p><p>• Ensures the necessary reports are completed and the CEO and/or DON are informed.</p><p>• Monitors consumer concerns, assists with the resolution and refers the matters to the CEO and/or DON.</p><p>Appendix 5 – Indicative Position Description for After Hours Coordinator 247</p><p>Appendix 5 – Indicative Position Description for After Hours Coordinator</p><p>• Assists in maintaining supportive relationships between staff, patients and is available for consultation and advice.</p><p>• Assists the DON with any projects or reports that may be necessary.</p><p>• If required to attend meetings during off duty periods, will be paid in accordance with this Agreement.</p><p>These responsibilities will be performed by the out-of-hours Grade 5 Supervisor in small country hospitals where the necessary resources are provided by the Employer.</p><p>Appendix 5 – Indicative Position Description for After Hours Coordinator 248 ```</p>',30)])])}const u=i(s,[["render",r]]);export{h as __pageData,u as default};
